package decisionMakingStatements;




public class IF_ELSE_IF {
	

		public static void main(String[] args) {
			// TODO Auto-generated method stub
			int a = 5;
			int b = 6;
			if(a > b) {
				System.out.println("a is greater than b");
			}
			else {
				System.out.println("b is greater than a");
			}
		}

	}
